import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Invoices","description":"","frontmatter":{},"headers":[],"relativePath":"features/invoices.md","filePath":"features/invoices.md"}'),n={name:"features/invoices.md"};function r(l,e,s,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="invoices" tabindex="-1">Invoices <a class="header-anchor" href="#invoices" aria-label="Permalink to &quot;Invoices&quot;">​</a></h1><p>Invoices are at the core of MyCompanyDesk. Create professional invoices, send them to customers with payment links, and track payments through to completion.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The invoices page shows all your invoices with filtering and search capabilities. Use the status tabs to quickly view:</p><ul><li><strong>All</strong> — Every invoice</li><li><strong>Draft</strong> — Created but not sent</li><li><strong>Sent</strong> — Delivered to customers</li><li><strong>Overdue</strong> — Past due date, unpaid</li><li><strong>Paid</strong> — Payment received</li><li><strong>Cancelled</strong> — Cancelled invoices</li></ul><h2 id="creating-an-invoice" tabindex="-1">Creating an invoice <a class="header-anchor" href="#creating-an-invoice" aria-label="Permalink to &quot;Creating an invoice&quot;">​</a></h2><h3 id="full-form" tabindex="-1">Full form <a class="header-anchor" href="#full-form" aria-label="Permalink to &quot;Full form&quot;">​</a></h3><ol><li>Go to <strong>Invoices &gt; New Invoice</strong></li><li>Select or create a <strong>customer</strong></li><li>Add <strong>line items</strong> with description, quantity, unit price, and VAT rate</li><li>Set the <strong>invoice date</strong> and <strong>due date</strong></li><li>Add optional <strong>notes</strong> or <strong>internal remarks</strong></li><li>Click <strong>Save</strong> to create a draft</li></ol><h3 id="quick-add" tabindex="-1">Quick Add <a class="header-anchor" href="#quick-add" aria-label="Permalink to &quot;Quick Add&quot;">​</a></h3><p>For faster creation:</p><ol><li>Click the quick-add button on the invoices list</li><li>Select a customer</li><li>Add items or choose a template</li><li>Save (and optionally send immediately)</li></ol><h3 id="from-a-template" tabindex="-1">From a template <a class="header-anchor" href="#from-a-template" aria-label="Permalink to &quot;From a template&quot;">​</a></h3><ol><li>When creating a new invoice, click <strong>Use Template</strong></li><li>Select a saved template</li><li>All line items are pre-filled — adjust as needed</li><li>Save and send</li></ol><h2 id="invoice-details" tabindex="-1">Invoice details <a class="header-anchor" href="#invoice-details" aria-label="Permalink to &quot;Invoice details&quot;">​</a></h2><p>Each invoice has a detail page showing:</p><ul><li>Customer information</li><li>Line items with subtotals</li><li>VAT breakdown</li><li>Total amount</li><li>Status and history</li><li>Payment link (if sent)</li></ul><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><h3 id="send" tabindex="-1">Send <a class="header-anchor" href="#send" aria-label="Permalink to &quot;Send&quot;">​</a></h3><p>Send the invoice to your customer via email. The email includes:</p><ul><li>A customizable message (based on your email template)</li><li>The invoice PDF as an attachment</li><li>A payment link for online payment</li></ul><h3 id="download-pdf" tabindex="-1">Download PDF <a class="header-anchor" href="#download-pdf" aria-label="Permalink to &quot;Download PDF&quot;">​</a></h3><p>Download the invoice as a professionally formatted PDF document. The PDF includes your company logo, branding colors, and all invoice details.</p><h3 id="mark-as-paid" tabindex="-1">Mark as paid <a class="header-anchor" href="#mark-as-paid" aria-label="Permalink to &quot;Mark as paid&quot;">​</a></h3><p>Manually confirm payment when a customer pays via bank transfer or other offline method.</p><h3 id="cancel" tabindex="-1">Cancel <a class="header-anchor" href="#cancel" aria-label="Permalink to &quot;Cancel&quot;">​</a></h3><p>Cancel an invoice that should no longer be paid. Cancelled invoices remain in your records for auditing purposes.</p><h3 id="duplicate" tabindex="-1">Duplicate <a class="header-anchor" href="#duplicate" aria-label="Permalink to &quot;Duplicate&quot;">​</a></h3><p>Create a copy of an existing invoice — useful for recurring billing to the same customer.</p><h3 id="send-reminder" tabindex="-1">Send reminder <a class="header-anchor" href="#send-reminder" aria-label="Permalink to &quot;Send reminder&quot;">​</a></h3><p>Send a payment reminder for overdue invoices.</p><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><p>Select multiple invoices from the list to perform actions in bulk:</p><ul><li><strong>Send</strong> — Send multiple draft invoices at once</li><li><strong>Mark as paid</strong> — Record payment for multiple invoices</li><li><strong>Archive</strong> — Move invoices to the archive</li><li><strong>Delete</strong> — Permanently remove invoices</li></ul><h2 id="payment-links" tabindex="-1">Payment links <a class="header-anchor" href="#payment-links" aria-label="Permalink to &quot;Payment links&quot;">​</a></h2><p>When you send an invoice, a unique payment link is generated. Your customer can:</p><ol><li>Click the link in the email</li><li>View the invoice in the <strong>customer portal</strong></li><li>Pay directly online</li></ol><p>Payment is automatically recorded and the invoice status updates to <strong>Paid</strong>.</p><h2 id="document-types" tabindex="-1">Document types <a class="header-anchor" href="#document-types" aria-label="Permalink to &quot;Document types&quot;">​</a></h2><p>The invoice module supports multiple document types:</p><ul><li><strong>Invoice</strong> — Standard billing document</li><li><strong>Credit note</strong> — Adjustment for refunds or corrections</li><li><strong>Reminder</strong> — Payment reminder for overdue invoices</li></ul><h2 id="filtering-and-search" tabindex="-1">Filtering and search <a class="header-anchor" href="#filtering-and-search" aria-label="Permalink to &quot;Filtering and search&quot;">​</a></h2><p>Use the filter bar to narrow down your invoices:</p><ul><li><strong>Status</strong> — Draft, Sent, Overdue, Paid, Cancelled</li><li><strong>Customer</strong> — Filter by specific customer</li><li><strong>Project</strong> — Filter by linked project</li><li><strong>Date range</strong> — Filter by invoice or due date</li><li><strong>Search</strong> — Search by invoice number, customer name, or description</li></ul><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>Export your invoices as CSV for use in Excel, Google Sheets, or your accounting software.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV export requires the <strong>Pro</strong> plan or higher.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Set up your <a href="/settings/email">email templates</a> before sending your first invoice</li><li>Use <a href="/features/recurring-invoices">recurring invoices</a> for regular billing</li><li>Check the <a href="/features/reports">reports</a> page for revenue insights</li><li>Enable <a href="/advanced/ai-features">AI suggestions</a> for smart description improvements</li></ul>',48)])])}const p=i(n,[["render",r]]);export{m as __pageData,p as default};
